import React, { useEffect, useState, useRef } from 'react';
import axios from 'axios';
import { Link } from 'react-router-dom';

const Home = () => {

  const [songs, setSongs] = useState([]);
  const [currentIndex, setCurrentIndex] = useState(-1);
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [duration, setDuration] = useState(0);
  const audioRef = useRef(null);

  const currentSong = currentIndex !== -1 ? songs[currentIndex] : null;

  useEffect(() => {
    const fetchSongs = async () => {
      try {
        const res = await axios.get('http://localhost:5000/api/songs');
        console.log("Danh sách nhạc từ server:", res.data);
        setSongs(res.data);
      } catch (err) {
        console.error(err);
      }
    };
    fetchSongs();
  }, []);

  const playSong = (index) => {
    setCurrentIndex(index);
    setIsPlaying(true);
  };

  const nextSong = () => {
    setCurrentIndex((currentIndex + 1) % songs.length);
    setIsPlaying(true);
  };

  const prevSong = () => {
    setCurrentIndex((currentIndex - 1 + songs.length) % songs.length);
    setIsPlaying(true);
  };

  const togglePlay = () => {
    if (isPlaying) audioRef.current.pause();
    else audioRef.current.play();
    setIsPlaying(!isPlaying);
  };

  const formatTime = (time) => {
    if (isNaN(time)) return "0:00";
    const min = Math.floor(time / 60);
    const sec = Math.floor(time % 60);
    return `${min}:${sec < 10 ? '0' : ''}${sec}`;
  };

  return (
    <div style={{ padding: '20px', maxWidth: '1200px', margin: '0 auto', paddingBottom: '150px' }}>

      <h2 style={{ textAlign: 'left', marginBottom: '30px', fontWeight: 'bold' }}>
        KHÁM PHÁ ÂM NHẠC
      </h2>

      {/* GRID LAYOUT */}
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(200px, 1fr))', gap: '25px' }}>
        {songs.map((song, index) => (
          <div key={song._id} style={cardStyle}>

            <div style={{ position: 'relative', overflow: 'hidden', borderRadius: '10px' }}>
              <img
                src={`http://localhost:5000${song.imageUrl}`}
                style={{ width: '100%', height: '200px', objectFit: 'cover' }}
                alt="cover"
              />
              <button onClick={() => playSong(index)} style={hoverPlayBtn}>▶</button>
            </div>

            <h4 style={{ margin: '15px 0 5px 0', whiteSpace: 'nowrap', overflow: 'hidden', textOverflow: 'ellipsis' }}>
              {song.title}
            </h4>

            <p style={{ fontSize: '14px', color: '#888', margin: '0 0 10px 0' }}>
              {song.artist}
            </p>

            {/* LINK VÀO PROFILE QUA TÊN USER */}
            {/* Tìm đoạn link Profile trong Home.js và sửa thành: */}
            <div style={{ fontSize: '12px', color: '#28a745', borderTop: '1px solid #eee', paddingTop: '8px' }}>
                Đăng bởi: 
                {song.userId ? (
                    // Nếu có userId thì mới cho link tới Profile
                    <Link 
                        to={`/profile/${song.userId}`} 
                        style={{ marginLeft: '5px', fontWeight: 'bold', color: '#28a745', textDecoration: 'none' }}
                    >
                        {song.uploaderName || "Người dùng"} 👤
                    </Link>
                ) : (
                    // Nếu không có (bài hát cũ), chỉ hiện tên hoặc chữ "Hệ thống"
                    <span style={{ marginLeft: '5px', color: '#888', fontStyle: 'italic' }}>
                        Admin (Dữ liệu cũ)
                    </span>
                )}
            </div>

          </div>
        ))}
      </div>

      {/* PLAYER CỐ ĐỊNH (Bottom) */}
      {currentSong && (
        <div style={playerContainerStyle}>

          <div style={{ display: 'flex', alignItems: 'center', width: '30%' }}>
            <img
              src={`http://localhost:5000${currentSong.imageUrl}`}
              style={{ width: '55px', height: '55px', borderRadius: '5px', marginRight: '15px' }}
              alt=""
            />
            <div style={{ textAlign: 'left' }}>
              <div style={{ fontWeight: 'bold', fontSize: '15px' }}>{currentSong.title}</div>
              <div style={{ fontSize: '13px', color: '#b3b3b3' }}>{currentSong.artist}</div>
            </div>
          </div>

          <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', width: '40%' }}>
            <div style={{ display: 'flex', alignItems: 'center', gap: '30px', marginBottom: '5px' }}>
              <button onClick={prevSong} style={btnIcon}>⏮</button>
              <button onClick={togglePlay} style={btnMain}>{isPlaying ? '⏸' : '▶'}</button>
              <button onClick={nextSong} style={btnIcon}>⏭</button>
            </div>

            <div style={{ display: 'flex', alignItems: 'center', width: '100%', gap: '10px' }}>
              <span style={{ fontSize: '12px' }}>{formatTime(currentTime)}</span>
              <input
                type="range"
                min="0"
                max={duration || 0}
                value={currentTime}
                onChange={(e) => audioRef.current.currentTime = e.target.value}
                style={{ flex: 1, accentColor: '#28a745' }}
              />
              <span style={{ fontSize: '12px' }}>{formatTime(duration)}</span>
            </div>

            <audio
              ref={audioRef}
              src={`http://localhost:5000${currentSong.songUrl}`}
              autoPlay
              onEnded={nextSong}
              onTimeUpdate={() => setCurrentTime(audioRef.current.currentTime)}
              onLoadedMetadata={() => setDuration(audioRef.current.duration)}
            />
          </div>

          <div style={{ width: '30%' }}></div>

        </div>
      )}

    </div>
  );
};

const cardStyle = {
  background: '#fff',
  padding: '15px',
  borderRadius: '15px',
  boxShadow: '0 4px 15px rgba(0,0,0,0.05)',
  transition: '0.3s'
};

const hoverPlayBtn = {
  position: 'absolute',
  bottom: '10px',
  right: '10px',
  background: '#28a745',
  color: '#fff',
  border: 'none',
  width: '40px',
  height: '40px',
  borderRadius: '50%',
  cursor: 'pointer',
  fontSize: '18px',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  boxShadow: '0 4px 10px rgba(0,0,0,0.3)'
};

const playerContainerStyle = {
  position: 'fixed',
  bottom: 0,
  left: 0,
  right: 0,
  background: '#181818',
  color: '#fff',
  padding: '15px 40px',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  zIndex: 1000
};

const btnIcon = {
  background: 'none',
  border: 'none',
  color: '#fff',
  fontSize: '28px',
  cursor: 'pointer'
};

const btnMain = {
  background: '#fff',
  border: 'none',
  color: '#000',
  width: '45px',
  height: '45px',
  borderRadius: '50%',
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center'
};

export default Home;
